"use strict";(self.webpackChunkvue_ellipse_progress_docs=self.webpackChunkvue_ellipse_progress_docs||[]).push([[58],{9059:(t,e,o)=>{o.r(e),o.d(e,{data:()=>a});const a={key:"v-00aada3d",path:"/guide/options/",title:"Options overview",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:3,title:"colorFill",slug:"colorfill",children:[]},{level:3,title:"emptyColorFill",slug:"emptycolorfill",children:[]},{level:3,title:"legendClass",slug:"legendclass",children:[]},{level:3,title:"data",slug:"data",children:[]}],git:{updatedTime:1651433613e3,contributors:[{name:"Sergej Atamantschuk",email:"sergejatam@gmail.com",commits:18}]},filePathRelative:"guide/options/README.md"}},1174:(t,e,o)=>{o.r(e),o.d(e,{default:()=>n});var a=o(6252);const s=[(0,a.uE)('<h1 id="options-overview" tabindex="-1"><a class="header-anchor" href="#options-overview" aria-hidden="true">#</a> Options overview</h1><p>The <strong><a href="#progress"><code>progress</code></a></strong> is the only required property, and you are ready to go with just following line:</p><div class="language-html ext-html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>ve-progress</span> <span class="token attr-name">:progress</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>progress<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n</code></pre></div><blockquote><p>Also make sure to check <strong><a href="#slot-options">slot options</a></strong></p></blockquote><table><thead><tr><th>Prop</th><th>Type</th><th>Values</th><th>Default</th></tr></thead><tbody><tr><td><strong><a href="#progress"><code>progress</code></a></strong></td><td>Number</td><td>[-100, 100]</td><td></td></tr><tr><td><strong><a href="#size"><code>size</code></a></strong></td><td>Number</td><td>&gt;=0</td><td>200</td></tr><tr><td><strong><a href="#line"><code>line</code></a></strong></td><td>String</td><td>&quot;round | square | butt&quot;</td><td>&quot;round&quot;</td></tr><tr><td><strong><a href="#thickness"><code>thickness</code></a></strong></td><td>Number | String</td><td>&gt;=0 as Number or percent value as String</td><td>&quot;5%&quot;</td></tr><tr><td><strong><a href="#linemode"><code>lineMode</code></a></strong></td><td>String</td><td>&quot;center | out | out-over | in | in-over | top | bottom [offset]&quot;</td><td>&quot;center&quot;</td></tr><tr><td><strong><a href="#lineposition"><code>linePosition</code></a></strong></td><td>String</td><td>&quot;center | out | in [offset]&quot;</td><td>&quot;center&quot;</td></tr><tr><td><strong><a href="#emptylineposition"><code>emptyLinePosition</code></a></strong></td><td>String</td><td>&quot;center | out | in [offset]&quot;</td><td>&quot;center&quot;</td></tr><tr><td><strong><a href="#emptythickness"><code>emptyThickness</code></a></strong></td><td>Number | String</td><td>&gt;=0 as Number or percent value as String</td><td>&quot;5%&quot;</td></tr><tr><td><strong><a href="#color"><code>color</code></a></strong></td><td>String | Object</td><td>any color as String or Object to specify gradient (see details)</td><td>&quot;#3f79ff&quot;</td></tr><tr><td><strong><a href="#colorfill"><code>colorFill</code></a></strong></td><td>String | Object</td><td>same as <code>color</code></td><td>&quot;transparent&quot;</td></tr><tr><td><strong><a href="#emptycolor"><code>emptyColor</code></a></strong></td><td>String | Object</td><td>same as <code>color</code></td><td>&quot;#e6e9f0&quot;</td></tr><tr><td><strong><a href="#emptycolorfill"><code>emptyColorFill</code></a></strong></td><td>String | Object</td><td>same as <code>color</code></td><td>&quot;transparent&quot;</td></tr><tr><td><strong><a href="#hideLegend"><code>hideLegend</code></a></strong></td><td>Boolean</td><td></td><td>true</td></tr><tr><td><strong><a href="#legend"><code>legend</code></a></strong></td><td>Number | String</td><td>any number, accepts a <code>.</code> or <code>&quot;,&quot;</code> as decimals delimiter and simple formatting</td><td></td></tr><tr><td><strong><a href="#legendformatter"><code>legendFormatter</code></a></strong></td><td>Function</td><td>Function that returns formatted value</td><td></td></tr><tr><td><strong><a href="#animation"><code>animation</code></a></strong></td><td>String</td><td>&quot;default | rs | loop | reverse | bounce [duration delay]&quot;</td><td>&quot;default 1000 400&quot;</td></tr><tr><td><strong><a href="#loading"><code>loading</code></a></strong></td><td>Boolean</td><td></td><td>false</td></tr><tr><td><strong><a href="#loader"><code>loader</code></a></strong></td><td>Object</td><td>{ [thickness, color, lineMode, line, opacity ]}</td><td></td></tr><tr><td><strong><a href="#determinate"><code>determinate</code></a></strong></td><td>Boolean</td><td></td><td>false</td></tr><tr><td><strong><a href="#nodata"><code>noData</code></a></strong></td><td>Boolean</td><td></td><td>false</td></tr><tr><td><strong><a href="#angle"><code>angle</code></a></strong></td><td>Number</td><td>any Number</td><td>-90</td></tr><tr><td><strong><a href="#fontsize"><code>fontSize</code></a></strong></td><td>String</td><td>any valid CSS value</td><td>&quot;1rem&quot;</td></tr><tr><td><strong><a href="#fontsize"><code>fontColor</code></a></strong></td><td>String</td><td>any valid CSS value</td><td>&quot;gray&quot;</td></tr><tr><td><strong><a href="#legendclass"><code>legendClass</code></a></strong></td><td>String</td><td>any</td><td></td></tr><tr><td><strong><a href="#dash"><code>dash</code></a></strong></td><td>String</td><td>&quot;[strict] count spacing&quot;</td><td></td></tr><tr><td><strong><a href="#half"><code>half</code></a></strong></td><td>Boolean</td><td></td><td>false</td></tr><tr><td><strong><a href="#gap"><code>gap</code></a></strong></td><td>Number</td><td>any Number that defines the gap between multiple circles in pixel</td><td>0</td></tr><tr><td><strong><a href="#dot"><code>dot</code></a></strong></td><td>String | Number | Object</td><td>Accepts size, color and other styles as Number, descriptive string <code>&quot;size [color]&quot;</code> or object <code>{size [, backgroundColor, widht, borderRadius ...]}</code></td><td>0</td></tr><tr><td><strong><a href="#reverse"><code>reverse</code></a></strong></td><td>Boolean</td><td></td><td>false</td></tr><tr><td><strong><a href="#data"><code>data</code></a></strong></td><td>Array</td><td>defines multiple circles, takes as values Objects with almost all props defined above</td><td></td></tr></tbody></table><ul><li><h3 id="colorfill" tabindex="-1"><a class="header-anchor" href="#colorfill" aria-hidden="true">#</a> <code>colorFill</code></h3></li></ul><h6 id="animated-✔️" tabindex="-1"><a class="header-anchor" href="#animated-✔️" aria-hidden="true">#</a> Animated: ✔️</h6><p>Defines the fill color of the progress circle. Takes the same value as <strong><a href="#color"><code>color</code></a></strong></p><br><ul><li><h3 id="emptycolorfill" tabindex="-1"><a class="header-anchor" href="#emptycolorfill" aria-hidden="true">#</a> <code>emptyColorFill</code></h3></li></ul><h6 id="animated-✔️-1" tabindex="-1"><a class="header-anchor" href="#animated-✔️-1" aria-hidden="true">#</a> Animated: ✔️</h6><p>Defines the fill color of the empty circle. Takes the same value as <strong><a href="#color"><code>color</code></a></strong></p><br><ul><li><h3 id="legendclass" tabindex="-1"><a class="header-anchor" href="#legendclass" aria-hidden="true">#</a> <code>legendClass</code></h3></li></ul><p>Adds class to the circles legend to give you the possibility to style it.</p><br><ul><li><h3 id="data" tabindex="-1"><a class="header-anchor" href="#data" aria-hidden="true">#</a> <code>data</code></h3></li></ul><p>You can specify 2 or more circles as Objects in an array as <code>data</code>. For each circle you can use almost every available property. It is not necessary to specify all properties, they will be merged with global props, the specified props will overwrite the global. The circles are rendered inside each other.</p><blockquote><p>❗ Excluded props: <strong><a href="#lineMode"><code>lineMode</code></a></strong>, <strong><a href="#emptyThickness"><code>emptyThickness</code></a></strong>, <strong><a href="#legend"><code>legend</code></a></strong>. These properties will be ignored, if <code>data</code> is specified. The legend of this circle is also not shown.</p></blockquote><h6 id="example-📜" tabindex="-1"><a class="header-anchor" href="#example-📜" aria-hidden="true">#</a> Example: 📜</h6><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token operator">&lt;</span><span class="token operator">!</span><span class="token operator">--</span> <span class="token keyword">this</span> props are applied to all circles<span class="token punctuation">,</span> <span class="token keyword">if</span> not overwritten <span class="token keyword">in</span> <span class="token string">&quot;data&quot;</span><span class="token operator">--</span><span class="token operator">&gt;</span>\n<span class="token operator">&lt;</span>ve<span class="token operator">-</span>progress color<span class="token operator">=</span><span class="token string">&quot;blue&quot;</span> animation<span class="token operator">=</span><span class="token string">&quot;loop 500&quot;</span> <span class="token operator">...</span>  <span class="token operator">:</span>data<span class="token operator">=</span><span class="token string">&quot;data&quot;</span><span class="token operator">/</span><span class="token operator">&gt;</span>\n\n<span class="token literal-property property">data</span><span class="token operator">:</span> <span class="token punctuation">[</span>\n  <span class="token punctuation">{</span>\n    <span class="token literal-property property">progress</span><span class="token operator">:</span> <span class="token number">50</span><span class="token punctuation">,</span> <span class="token comment">// required for each circle</span>\n    <span class="token literal-property property">color</span><span class="token operator">:</span> <span class="token string">&quot;red&quot;</span><span class="token punctuation">,</span>  <span class="token comment">// will overwrite global progress color</span>\n    <span class="token operator">...</span>           <span class="token comment">// other options will be merged with global</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token punctuation">{</span>\n    <span class="token literal-property property">progress</span><span class="token operator">:</span> <span class="token number">50</span><span class="token punctuation">,</span> <span class="token comment">// required for each circle</span>\n    <span class="token literal-property property">animation</span><span class="token operator">:</span> <span class="token string">&quot;rs 1500 500&quot;</span>  <span class="token comment">// you can set almost any option that will be specific to this circle</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><img width="100" height="100" src="https://github.com/setaman/Bilder/blob/master/vue-ellipse-data.PNG" alt="multiple circles demo">',22)],r={},n=(0,o(3744).Z)(r,[["render",function(t,e){return(0,a.wg)(),(0,a.iD)("div",null,s)}]])}}]);